  ('customs-7fec267e-moex-00001', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列何者不符合經濟學概念？', '["經濟學不僅強調選擇，經濟學也重視誘因", "網路購物平臺上買賣雙方雖然看不到彼此，但這也是一種市場", "透過經濟體系的完整循環流程圖，並無法看出該經濟體的整體所得樣貌", "所謂的「均衡」並無好壞之別，也不包含任何的價值判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00002', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '依據下圖，下列敘述何者最能解釋經濟體為何從生產可能組合中的F點移動到C點？ 冰 A 箱 （ 台 ） F B D C 0 汽車（輛）', '["該國發現了新的油礦使汽車的使用成本下降", "汽車科技的進步使汽車生產的成本降低", "汽車的相對價格上升", "勞工逐漸緊缺，促使汽車生產成本上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00003', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '若甲國在生產商品B具比較利益，而乙國在生產商品A具比較利益，一旦兩國依循比較利益與專業 分工原則進行貿易，下列敘述何者正確？', '["兩國內之A、B產業皆將同時受益", "兩國內之A、B產業皆將同時受害", "甲國之A產業將受益，B產業則受害；乙國之A產業將受害，B產業則受益", "甲國之A產業將受害，B產業則受益；乙國之A產業將受益，B產業則受害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00004', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設晶片生產過程必須經歷設計與製造兩階段，才能創造出價值 1 元的完整晶片商品，而任一單獨 的設計或製造過程，則皆無任何市場價值。如果甲公司設計一個晶片需2小時，製造一個晶片則需1 小時；而乙公司設計一個晶片需3小時，製造一個晶片則需2小時。假設兩公司1週各可工作45個 小時，則兩公司透過比較利益原則與專業分工合作下，可較其各自獨立生產下額外增加 之最大 共同產值。', '["5個", "3個", "1個", "0個"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00005', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設蘋果的市場需求曲線為負斜率，當蘋果的價格上升時，下列敘述何者正確？', '["蘋果的市場需求會增加", "蘋果的市場需求會減少", "蘋果的市場需求量會增加", "蘋果的市場需求量會減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
